(131, 'Ensino Médio', 'Língua Portuguesa', '3ª Série', NULL, 'AE3', 'Analisar as peculiaridades estruturais e estilísticas de diferentes gêneros literários, identificando o estilo, os temas e as influências dos movimentos literários aos quais pertencem.', NOW()),
